+fn post_commit_probe_cancelled_error(operation: &'static str, detail: &str) -> DbError {
+    DbError::ResourceBusy(format!(
+        "{operation} durability probe cancelled after commit for {detail}"
+    ))
+}
+
+fn post_commit_probe_panicked_error(
